    const [r, c] = k.split(",").map(Number);
    const cell: Cell = [r, c];
    if (count === 3 || (count === 2 && liveSet.has(k))) {
      result.push(cell);
    }
  }

  result.sort((a, b) => a[1] - b[1] || a[0] - b[0]);
  return result;
}
